//! 空间碰撞检测 - 高性能 Rust 实现
//!
//! 使用空间哈希网格进行快速碰撞查询
//! 适用于大量移动实体的碰撞检测场景

use hashbrown::{HashMap, HashSet};
use wasm_bindgen::prelude::*;

/// 实体数据
#[derive(Clone, Copy, Debug)]
struct Entity {
    id: u32,
    x: f32,
    y: f32,
    radius: f32,
    group: u32,
}

/// 空间哈希网格
#[wasm_bindgen]
pub struct SpatialHash {
    cell_size: f32,
    grid: HashMap<(i32, i32), Vec<u32>>,
    entities: HashMap<u32, Entity>,
}
